// 3D Earth Map Component - Dũng
import React, { useEffect, useRef, useState } from 'react';
import * as THREE from 'three';
import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls.js';
import './EarthMap.css';

const EarthMap = () => {
  const containerRef = useRef(null);
  const sceneRef = useRef(null);
  const earthRef = useRef(null);
  const controlsRef = useRef(null);
  const [isLoaded, setIsLoaded] = useState(false);

  useEffect(() => {
    if (!containerRef.current) return;

    // Scene setup
    const scene = new THREE.Scene();
    sceneRef.current = scene;

    // Camera setup
    const camera = new THREE.PerspectiveCamera(
      45,
      containerRef.current.clientWidth / containerRef.current.clientHeight,
      0.1,
      1000
    );
    camera.position.z = 5;

    // Renderer setup
    const renderer = new THREE.WebGLRenderer({ 
      antialias: true, 
      alpha: true 
    });
    renderer.setSize(
      containerRef.current.clientWidth,
      containerRef.current.clientHeight
    );
    renderer.setPixelRatio(window.devicePixelRatio);
    containerRef.current.appendChild(renderer.domElement);

    // Controls
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.05;
    controls.enableZoom = true;
    controls.minDistance = 2.5;
    controls.maxDistance = 10;
    controlsRef.current = controls;

    // Lighting
    const ambientLight = new THREE.AmbientLight(0x404040, 0.5);
    scene.add(ambientLight);

    const sunLight = new THREE.DirectionalLight(0xffffff, 1.5);
    sunLight.position.set(5, 3, 5);
    scene.add(sunLight);

    // Create Earth
    const earthGeometry = new THREE.SphereGeometry(1.5, 64, 64);

    // Earth texture using procedural generation
    const earthTexture = createEarthTexture();

    const earthMaterial = new THREE.MeshPhongMaterial({
      map: earthTexture,
      bumpMap: earthTexture,
      bumpScale: 0.05,
      specularMap: earthTexture,
      specular: new THREE.Color(0x333333),
      shininess: 5
    });

    const earth = new THREE.Mesh(earthGeometry, earthMaterial);
    scene.add(earth);
    earthRef.current = earth;

    // Atmosphere glow
    const atmosphereGeometry = new THREE.SphereGeometry(1.6, 64, 64);
    const atmosphereMaterial = new THREE.ShaderMaterial({
      vertexShader: `
        varying vec3 vNormal;
        void main() {
          vNormal = normalize(normalMatrix * normal);
          gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
        }
      `,
      fragmentShader: `
        varying vec3 vNormal;
        void main() {
          float intensity = pow(0.7 - dot(vNormal, vec3(0, 0, 1.0)), 2.0);
          gl_FragColor = vec4(0.3, 0.6, 1.0, 1.0) * intensity;
        }
      `,
      blending: THREE.AdditiveBlending,
      side: THREE.BackSide,
      transparent: true
    });

    const atmosphere = new THREE.Mesh(atmosphereGeometry, atmosphereMaterial);
    scene.add(atmosphere);

    // Stars background
    const starsGeometry = new THREE.BufferGeometry();
    const starsMaterial = new THREE.PointsMaterial({
      color: 0xffffff,
      size: 0.02,
      transparent: true
    });

    const starsVertices = [];
    for (let i = 0; i < 10000; i++) {
      const x = (Math.random() - 0.5) * 2000;
      const y = (Math.random() - 0.5) * 2000;
      const z = (Math.random() - 0.5) * 2000;
      starsVertices.push(x, y, z);
    }

    starsGeometry.setAttribute(
      'position',
      new THREE.Float32BufferAttribute(starsVertices, 3)
    );

    const stars = new THREE.Points(starsGeometry, starsMaterial);
    scene.add(stars);

    // Palmer Archipelago marker (positioned in Antarctica)
    const markerGeometry = new THREE.SphereGeometry(0.03, 32, 32);
    const markerMaterial = new THREE.MeshBasicMaterial({ 
      color: 0xFFD43B 
    });
    const marker = new THREE.Mesh(markerGeometry, markerMaterial);

    // Convert Antarctica position to 3D coordinates
    const antarcticaLat = -64.77;
    const antarcticaLon = -64.05;
    const markerPos = latLonToVector3(antarcticaLat, antarcticaLon, 1.52);
    marker.position.copy(markerPos);
    scene.add(marker);

    // Marker glow
    const markerGlowGeometry = new THREE.SphereGeometry(0.08, 32, 32);
    const markerGlowMaterial = new THREE.MeshBasicMaterial({
      color: 0xFFD43B,
      transparent: true,
      opacity: 0.3
    });
    const markerGlow = new THREE.Mesh(markerGlowGeometry, markerGlowMaterial);
    markerGlow.position.copy(markerPos);
    scene.add(markerGlow);

    // Animation loop
    const animate = () => {
      requestAnimationFrame(animate);

      if (earthRef.current) {
        earthRef.current.rotation.y += 0.001;
      }

      if (controlsRef.current) {
        controlsRef.current.update();
      }

      renderer.render(scene, camera);
    };
    animate();

    // Mark as loaded
    setIsLoaded(true);

    // Handle resize
    const handleResize = () => {
      if (!containerRef.current) return;

      camera.aspect =
        containerRef.current.clientWidth / containerRef.current.clientHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(
        containerRef.current.clientWidth,
        containerRef.current.clientHeight
      );
    };

    window.addEventListener('resize', handleResize);

    // Cleanup
    return () => {
      window.removeEventListener('resize', handleResize);
      containerRef.current?.removeChild(renderer.domElement);
      renderer.dispose();
      earthGeometry.dispose();
      earthMaterial.dispose();
      atmosphereGeometry.dispose();
      atmosphereMaterial.dispose();
      starsGeometry.dispose();
      starsMaterial.dispose();
    };
  }, []);

  const latLonToVector3 = (lat, lon, radius) => {
    const phi = (90 - lat) * (Math.PI / 180);
    const theta = (lon + 180) * (Math.PI / 180);

    const x = -(radius * Math.sin(phi) * Math.cos(theta));
    const z = (radius * Math.sin(phi) * Math.sin(theta));
    const y = (radius * Math.cos(phi));

    return new THREE.Vector3(x, y, z);
  };

  const createEarthTexture = () => {
    const canvas = document.createElement('canvas');
    canvas.width = 2048;
    canvas.height = 1024;
    const ctx = canvas.getContext('2d');

    // Ocean gradient
    const oceanGradient = ctx.createRadialGradient(1024, 512, 0, 1024, 512, 1024);
    oceanGradient.addColorStop(0, '#1a5fb4');
    oceanGradient.addColorStop(0.5, '#0d47a1');
    oceanGradient.addColorStop(1, '#062e5a');
    ctx.fillStyle = oceanGradient;
    ctx.fillRect(0, 0, 2048, 1024);

    // Simplified continent shapes
    const continents = [
      // North America
      { x: 400, y: 300, w: 400, h: 300 },
      // South America  
      { x: 550, y: 600, w: 200, h: 300 },
      // Europe
      { x: 1000, y: 250, w: 250, h: 200 },
      // Africa
      { x: 1050, y: 500, w: 250, h: 350 },
      // Asia
      { x: 1300, y: 300, w: 500, h: 350 },
      // Australia
      { x: 1600, y: 700, w: 200, h: 150 },
      // Antarctica
      { x: 1024, y: 950, w: 1400, h: 100 }
    ];

    continents.forEach(cont => {
      const gradient = ctx.createRadialGradient(
        cont.x + cont.w/2, cont.y + cont.h/2, 0,
        cont.x + cont.w/2, cont.y + cont.h/2, Math.max(cont.w, cont.h)
      );
      gradient.addColorStop(0, '#4a9c5d');
      gradient.addColorStop(0.5, '#2d6a4f');
      gradient.addColorStop(1, '#1a4036');

      ctx.beginPath();
      ctx.ellipse(cont.x + cont.w/2, cont.y + cont.h/2, cont.w/2, cont.h/2, 0, 0, Math.PI * 2);
      ctx.fillStyle = gradient;
      ctx.fill();
    });

    // Add some texture detail
    for (let i = 0; i < 5000; i++) {
      const x = Math.random() * 2048;
      const y = Math.random() * 1024;
      ctx.fillStyle = `rgba(255, 255, 255, ${Math.random() * 0.1})`;
      ctx.fillRect(x, y, 2, 2);
    }

    const texture = new THREE.CanvasTexture(canvas);
    return texture;
  };

  const handleZoomIn = () => {
    if (zoomLevel < 3) {
      setIsZooming(true);
      setTimeout(() => {
        setZoomLevel(prev => Math.min(prev + 0.5, 3));
        setIsZooming(false);
      }, 300);
    }
  };

  const handleZoomOut = () => {
    if (zoomLevel > 1) {
      setIsZooming(true);
      setTimeout(() => {
        setZoomLevel(prev => Math.max(prev - 0.5, 1));
        setIsZooming(false);
      }, 300);
    }
  };

  return (
    <div className="earth-map-container">
      <div className="earth-map-wrapper">
        <canvas 
          ref={canvasRef} 
          width={600} 
          height={400}
          className={`earth-canvas ${isZooming ? 'zooming' : ''}`}
        />
        <div className="zoom-controls">
          <button onClick={handleZoomOut} disabled={zoomLevel <= 1}>
            🔍 Zoom Out
          </button>
          <span>Zoom: {zoomLevel}x</span>
          <button onClick={handleZoomIn} disabled={zoomLevel >= 3}>
            🔍 Zoom In
          </button>
        </div>
      </div>
      <p className="earth-map-description">
        📍 Palmer Archipelago, Antarctica - Home to three penguin species
      </p>
    </div>
  );
};

export default EarthMap;
